#include <stdio.h>

int main() {
    int age = 20;         // Bir insanın yaşını saxlayır
    float height = 1.75;  // Boyu metr ilə saxlayır
    char grade = 'A';     // Tələbənin qiymətini saxlayır
    double pi = 3.14159;  // Dəqiq kəsr ədəd saxlayır
    const int maxScore = 100; // Sabit dəyər, dəyişdirilə bilməz

    printf("Yaş: %d\n", age);
    printf("Boy: %.2f metr\n", height);
    printf("Qiymət: %c\n", grade);
    printf("Pi: %.5f\n", pi);
    printf("Maksimum xal: %d\n", maxScore);

    return 0;
}
// Çıxış:
// Yaş: 20
// Boy: 1.75 metr
// Qiymət: A
// Pi: 3.14159
// Maksimum xal: 100

#include <stdio.h>

int main() {
    int age = 20;         // Stores a person’s age
    float height = 1.75;  // Stores height in meters
    char grade = 'A';     // Stores a student’s grade
    double pi = 3.14159;  // Stores a precise decimal number
    const int maxScore = 100; // A constant value, can’t be changed

    printf("Age: %d\n", age);
    printf("Height: %.2f meters\n", height);
    printf("Grade: %c\n", grade);
    printf("Pi: %.5f\n", pi);
    printf("Max Score: %d\n", maxScore);

    return 0;
}
// Output:
// Age: 20
// Height: 1.75 meters
// Grade: A
// Pi: 3.14159
// Max Score: 100

